var hostname = location.hostname;
var STORAGE_KEY = 'domo_shortcuts_' + hostname;
var PANEL_ID = '__domo_shortcuts_panel__';
var TOGGLE_STYLE_ID = '__domo_toggle_style__';

// ── State ──
var shortcuts = [];
try { shortcuts = JSON.parse(localStorage.getItem(STORAGE_KEY) || '[]'); } catch(e) { shortcuts = []; }
var panelOpen = false;
var panelHost = null;
var panelShadow = null;
var editing = null; // null or shortcut id
var recording = false;
var recordedCombo = '';

var BUILTIN = [
  { shortcut: 'Alt+H', label: 'Toggle hide mode', builtin: true },
  { shortcut: 'Alt+K', label: 'Toggle shortcuts panel', builtin: true }
];

// ── Persistence ──
function save() {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(shortcuts));
}

function genId() {
  var b = new Uint8Array(4);
  crypto.getRandomValues(b);
  return 's_' + Array.from(b, function(x) { return x.toString(16).padStart(2, '0'); }).join('');
}

// ── Key Normalization ──
function normalizeEvent(e) {
  var parts = [];
  if (e.ctrlKey) parts.push('Ctrl');
  if (e.altKey) parts.push('Alt');
  if (e.shiftKey) parts.push('Shift');
  if (e.metaKey) parts.push('Meta');
  var key = e.key;
  if (!key) return '';
  if (key === ' ') key = 'Space';
  if (key.length === 1) key = key.toUpperCase();
  if (['Control', 'Alt', 'Shift', 'Meta'].indexOf(key) === -1) parts.push(key);
  return parts.join('+');
}

function hasModifier(combo) {
  return combo.indexOf('Ctrl+') !== -1 || combo.indexOf('Alt+') !== -1 || combo.indexOf('Shift+') !== -1 || combo.indexOf('Meta+') !== -1;
}

function isTextInput(el) {
  if (!el) return false;
  var tag = el.tagName;
  if (tag === 'INPUT' || tag === 'TEXTAREA' || tag === 'SELECT') return true;
  if (el.isContentEditable) return true;
  return false;
}

// ── Action Executors ──
function exec(s) {
  try {
    if (s.action === 'navigate') {
      var url = s.config.url || '';
      if (url.startsWith('/') || url.startsWith('#')) url = location.origin + url;
      location.href = url;
    } else if (s.action === 'click') {
      var el = document.querySelector(s.config.selector);
      if (el) el.click();
    } else if (s.action === 'scroll') {
      if (s.config.selector) {
        var el = document.querySelector(s.config.selector);
        if (el) el.scrollIntoView({ behavior: 'smooth', block: 'center' });
      } else if (s.config.position === 'bottom') {
        window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' });
      } else {
        window.scrollTo({ top: 0, behavior: 'smooth' });
      }
    } else if (s.action === 'toggle') {
      var el = document.querySelector(s.config.selector);
      if (el) {
        var hidden = el.getAttribute('data-domo-hidden');
        if (hidden) {
          el.removeAttribute('data-domo-hidden');
          el.style.removeProperty('display');
        } else {
          el.setAttribute('data-domo-hidden', '1');
          el.style.setProperty('display', 'none', 'important');
        }
      }
    } else if (s.action === 'js') {
      new Function(s.config.code)();
    }
  } catch (err) {
    console.warn('[domo shortcuts] action failed:', err);
  }
}

// ── Keyboard Listener ──
api.addEventListener(window, 'keydown', function(e) {
  try {
    if (isTextInput(document.activeElement)) return;
    var combo = normalizeEvent(e);
    if (!combo || !hasModifier(combo)) return;
    for (var i = 0; i < shortcuts.length; i++) {
      if (shortcuts[i].shortcut === combo) {
        e.preventDefault();
        e.stopPropagation();
        exec(shortcuts[i]);
        return;
      }
    }
  } catch(err) {}
}, { capture: true });

// ── Element Picker (inlined) ──
function computeSelector(el) {
  if (!(el instanceof Element)) return null;
  if (el.id && !el.id.startsWith('__domo')) return '#' + CSS.escape(el.id);
  var testId = el.getAttribute('data-testid') || el.getAttribute('data-test-id');
  if (testId) return '[data-testid="' + testId.replace(/"/g, '\\"') + '"]';
  var parts = [];
  var cur = el;
  for (var i = 0; i < 6 && cur && cur.nodeType === 1 && cur !== document.body; i++) {
    var tag = cur.tagName.toLowerCase();
    if (!tag) break;
    var parent = cur.parentElement;
    if (!parent) { parts.unshift(tag); break; }
    var siblings = Array.from(parent.children).filter(function(c) { return c.tagName === cur.tagName; });
    var idx = siblings.indexOf(cur) + 1;
    var piece = siblings.length > 1 ? tag + ':nth-of-type(' + idx + ')' : tag;
    parts.unshift(piece);
    if (parent.id && !parent.id.startsWith('__domo')) {
      parts.unshift('#' + CSS.escape(parent.id));
      break;
    }
    cur = parent;
  }
  return parts.join(' > ');
}

function pickElement() {
  return new Promise(function(resolve) {
    var active = true;
    var overlay = document.createElement('div');
    overlay.style.cssText = 'position:fixed;inset:0;z-index:2147483646;cursor:crosshair;background:rgba(0,0,0,0.02);pointer-events:none;';
    var highlight = document.createElement('div');
    highlight.style.cssText = 'position:fixed;z-index:2147483647;pointer-events:none;border:2px solid #58a6ff;border-radius:6px;box-shadow:0 0 0 4px rgba(88,166,255,.15);';
    function isOurUI(el) {
      while (el) {
        if (el.id && (el.id.startsWith('__domo') || el.getAttribute && el.getAttribute('data-domo'))) return true;
        el = el.parentElement;
      }
      return false;
    }
    function cleanup() {
      active = false; overlay.remove(); highlight.remove();
      document.documentElement.style.cursor = '';
      window.removeEventListener('keydown', onKey, true);
      document.removeEventListener('mousemove', onMove, true);
      document.removeEventListener('click', onClick, true);
    }
    function onKey(e) { if (e.key === 'Escape') { e.preventDefault(); e.stopPropagation(); cleanup(); resolve(null); } }
    function onMove(e) {
      if (!active) return;
      var el = document.elementFromPoint(e.clientX, e.clientY);
      if (!el || isOurUI(el)) return;
      var r = el.getBoundingClientRect();
      highlight.style.left = Math.max(0, r.left) + 'px'; highlight.style.top = Math.max(0, r.top) + 'px';
      highlight.style.width = Math.max(0, r.width) + 'px'; highlight.style.height = Math.max(0, r.height) + 'px';
    }
    function onClick(e) {
      if (!active) return; e.preventDefault(); e.stopPropagation();
      var el = document.elementFromPoint(e.clientX, e.clientY);
      if (!el || isOurUI(el)) return; cleanup(); resolve(el);
    }
    document.body.appendChild(overlay); document.body.appendChild(highlight);
    document.documentElement.style.cursor = 'crosshair';
    window.addEventListener('keydown', onKey, true);
    document.addEventListener('mousemove', onMove, true);
    document.addEventListener('click', onClick, true);
  });
}

// ── Floating Panel ──
function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

function openPanel() {
  if (panelHost) closePanel();
  panelOpen = true; editing = null;
  panelHost = document.createElement('div');
  panelHost.id = PANEL_ID;
  panelHost.style.cssText = 'all:initial;position:fixed;bottom:16px;right:16px;z-index:2147483645;';
  panelShadow = panelHost.attachShadow({ mode: 'closed' });
  renderList();
  document.body.appendChild(panelHost);
  api.addEventListener(document, 'keydown', function(e) {
    if (e.key === 'Escape' && panelOpen && !recording) { e.stopPropagation(); closePanel(); }
  });
}

function closePanel() {
  panelOpen = false; editing = null; recording = false;
  if (panelHost) { panelHost.remove(); panelHost = null; panelShadow = null; }
}

function actionLabel(s) {
  if (s.action === 'navigate') return 'navigate';
  if (s.action === 'click') return 'click';
  if (s.action === 'scroll') return 'scroll';
  if (s.action === 'toggle') return 'toggle';
  if (s.action === 'js') return 'js';
  return s.action || '?';
}

function autoLabel(action, config) {
  if (action === 'navigate') return 'Navigate to ' + (config.url || '/');
  if (action === 'click') return 'Click ' + (config.selector || '?');
  if (action === 'scroll') return config.selector ? 'Scroll to ' + config.selector : 'Scroll to ' + (config.position || 'top');
  if (action === 'toggle') return 'Toggle ' + (config.selector || '?');
  if (action === 'js') return 'Run custom JS';
  return 'Shortcut';
}

function renderList() {
  if (!panelShadow) return;
  var items = '';
  // Built-in
  items += '<div class="section-label">Built-in</div>';
  BUILTIN.forEach(function(b) {
    items += '<div class="item item-dim"><div class="info"><span class="lbl">' + esc(b.label) + '</span></div><code>' + esc(b.shortcut) + '</code></div>';
  });
  // Custom
  items += '<div class="section-label" style="margin-top:10px">Custom' + (shortcuts.length > 0 ? ' (' + shortcuts.length + ')' : '') + '</div>';
  items += '<button class="btn bp" id="add-btn">+ Add Shortcut</button>';
  if (shortcuts.length === 0) {
    items += '<div class="empty">No custom shortcuts on ' + esc(hostname) + '.</div>';
  } else {
    items += '<div class="list">';
    shortcuts.forEach(function(s, i) {
      items += '<div class="item"><div class="info"><span class="lbl">' + esc(s.label || autoLabel(s.action, s.config)) + '</span>' +
        '<span class="tag">' + esc(actionLabel(s)) + '</span></div>' +
        '<code>' + esc(s.shortcut) + '</code>' +
        '<button class="btn bs edit-btn" data-i="' + i + '">Edit</button>' +
        '<button class="btn bs bd del-btn" data-i="' + i + '">&times;</button></div>';
    });
    items += '</div>';
    items += '<button class="btn bd bs" id="reset-btn" style="margin-top:8px">Reset All</button>';
  }
  panelShadow.innerHTML = '<style>' + panelCSS() + '</style>' +
    '<div class="panel"><div class="hdr"><span class="title">Keyboard Shortcuts</span><span class="sub">' + esc(hostname) + '</span>' +
    '<button class="x" id="close">&times;</button></div><div class="body">' + items + '</div></div>';
  // Wire
  panelShadow.getElementById('close').onclick = closePanel;
  panelShadow.getElementById('add-btn').onclick = function() { editing = null; renderForm(); };
  var rb = panelShadow.getElementById('reset-btn');
  if (rb) rb.onclick = function() { shortcuts = []; save(); renderList(); };
  panelShadow.querySelectorAll('.edit-btn').forEach(function(btn) {
    btn.onclick = function() { editing = shortcuts[parseInt(btn.dataset.i)].id; renderForm(); };
  });
  panelShadow.querySelectorAll('.del-btn').forEach(function(btn) {
    btn.onclick = function() { shortcuts.splice(parseInt(btn.dataset.i), 1); save(); renderList(); };
  });
}

function renderForm() {
  if (!panelShadow) return;
  var existing = null;
  if (editing) existing = shortcuts.find(function(s) { return s.id === editing; });
  var action = existing ? existing.action : 'navigate';
  var config = existing ? existing.config : {};
  recordedCombo = existing ? existing.shortcut : '';
  var label = existing ? (existing.label || '') : '';
  var title = existing ? 'Edit Shortcut' : 'New Shortcut';

  function configFields(act, cfg) {
    if (act === 'navigate') return '<label class="fl">URL (relative or absolute)</label><input id="cfg-url" class="fi" value="' + esc(cfg.url || '') + '" placeholder="/dashboard">';
    if (act === 'click') return '<label class="fl">CSS Selector</label><div class="row"><input id="cfg-sel" class="fi" style="flex:1" value="' + esc(cfg.selector || '') + '" placeholder=".btn-primary"><button class="btn bs" id="pick-btn">Pick</button></div>';
    if (act === 'scroll') return '<label class="fl">Scroll to</label><select id="cfg-pos" class="fi"><option value="top"' + (cfg.position !== 'bottom' && !cfg.selector ? ' selected' : '') + '>Top</option><option value="bottom"' + (cfg.position === 'bottom' ? ' selected' : '') + '>Bottom</option><option value="element"' + (cfg.selector ? ' selected' : '') + '>Element</option></select>' + (cfg.selector ? '<input id="cfg-sel" class="fi" value="' + esc(cfg.selector || '') + '" placeholder="#comments" style="margin-top:4px">' : '<div id="scroll-sel-wrap"></div>');
    if (act === 'toggle') return '<label class="fl">CSS Selector</label><div class="row"><input id="cfg-sel" class="fi" style="flex:1" value="' + esc(cfg.selector || '') + '" placeholder=".sidebar"><button class="btn bs" id="pick-btn">Pick</button></div>';
    if (act === 'js') return '<label class="fl">JavaScript code</label><textarea id="cfg-code" class="fi ta" rows="3" placeholder="document.body.classList.toggle(&apos;dark&apos;)">' + esc(cfg.code || '') + '</textarea>';
    return '';
  }

  var actions = ['navigate', 'click', 'scroll', 'toggle', 'js'];
  var actionLabels = { navigate: 'Navigate to URL', click: 'Click element', scroll: 'Scroll to position', toggle: 'Toggle visibility', js: 'Run JS snippet' };
  var radios = actions.map(function(a) {
    return '<label class="rl"><input type="radio" name="action" value="' + a + '"' + (a === action ? ' checked' : '') + '> ' + actionLabels[a] + '</label>';
  }).join('');

  panelShadow.innerHTML = '<style>' + panelCSS() + '</style>' +
    '<div class="panel"><div class="hdr"><span class="title">' + esc(title) + '</span>' +
    '<button class="x" id="cancel">Cancel</button></div><div class="body">' +
    '<label class="fl">Key combination</label>' +
    '<div class="rec" id="recorder" tabindex="0">' + (recordedCombo ? '<code>' + esc(recordedCombo) + '</code>' : '<span class="placeholder">Click here, then press keys...</span>') + '</div>' +
    '<div id="combo-err" class="err"></div>' +
    '<label class="fl" style="margin-top:10px">Action</label>' +
    '<div class="radios">' + radios + '</div>' +
    '<div id="config-area">' + configFields(action, config) + '</div>' +
    '<label class="fl" style="margin-top:10px">Label (optional)</label>' +
    '<input id="label-input" class="fi" value="' + esc(label) + '" placeholder="Auto-generated if empty">' +
    '<button class="btn bp" id="save-btn" style="margin-top:12px">' + (existing ? 'Save Changes' : 'Add Shortcut') + '</button>' +
    (existing ? '<button class="btn bd bs" id="form-del" style="margin-top:6px;width:100%">Delete this shortcut</button>' : '') +
    '</div></div>';

  // Wire cancel
  panelShadow.getElementById('cancel').onclick = function() { editing = null; recording = false; renderList(); };

  // Wire recorder
  var recEl = panelShadow.getElementById('recorder');
  var errEl = panelShadow.getElementById('combo-err');
  recEl.onclick = function() {
    recording = true;
    recEl.innerHTML = '<span class="placeholder">Press a key combination...</span>';
    errEl.textContent = '';
    recEl.focus();
  };
  recEl.addEventListener('keydown', function(e) {
    if (!recording) return;
    e.preventDefault(); e.stopPropagation();
    var combo = normalizeEvent(e);
    if (!combo || ['Ctrl', 'Alt', 'Shift', 'Meta'].indexOf(e.key) !== -1) return;
    recording = false;
    recordedCombo = combo;
    recEl.innerHTML = '<code>' + esc(combo) + '</code>';
    if (!hasModifier(combo)) {
      errEl.textContent = 'Must include a modifier (Ctrl, Alt, Shift, or Meta)';
      recordedCombo = '';
    } else {
      var dup = shortcuts.find(function(s) { return s.shortcut === combo && s.id !== editing; });
      if (dup) errEl.textContent = 'Already used: ' + (dup.label || autoLabel(dup.action, dup.config));
      else errEl.textContent = '';
    }
  });

  // Wire action radios
  panelShadow.querySelectorAll('input[name="action"]').forEach(function(radio) {
    radio.onchange = function() {
      action = radio.value;
      config = {};
      panelShadow.getElementById('config-area').innerHTML = configFields(action, config);
      wireConfigExtras();
    };
  });

  // Wire scroll position change
  function wireConfigExtras() {
    var posEl = panelShadow.getElementById('cfg-pos');
    if (posEl) {
      posEl.onchange = function() {
        var wrap = panelShadow.getElementById('scroll-sel-wrap');
        if (posEl.value === 'element' && wrap) {
          wrap.innerHTML = '<input id="cfg-sel" class="fi" placeholder="#comments" style="margin-top:4px">';
        } else if (wrap) {
          wrap.innerHTML = '';
        }
      };
    }
    var pickBtn = panelShadow.getElementById('pick-btn');
    if (pickBtn) {
      pickBtn.onclick = async function() {
        var el = await pickElement();
        if (el) {
          var sel = computeSelector(el);
          var inp = panelShadow.getElementById('cfg-sel');
          if (inp && sel) inp.value = sel;
        }
      };
    }
  }
  wireConfigExtras();

  // Wire save
  panelShadow.getElementById('save-btn').onclick = function() {
    if (!recordedCombo) { errEl.textContent = 'Record a key combination first'; return; }
    if (!hasModifier(recordedCombo)) { errEl.textContent = 'Must include a modifier key'; return; }
    var dup = shortcuts.find(function(s) { return s.shortcut === recordedCombo && s.id !== editing; });
    if (dup) { errEl.textContent = 'Already used by another shortcut'; return; }
    var builtinDup = BUILTIN.find(function(b) { return b.shortcut === recordedCombo; });
    if (builtinDup) { errEl.textContent = 'Conflicts with built-in: ' + builtinDup.label; return; }
    // Collect config
    var cfg = {};
    if (action === 'navigate') { cfg.url = (panelShadow.getElementById('cfg-url') || {}).value || ''; if (!cfg.url) return; }
    if (action === 'click' || action === 'toggle') { cfg.selector = (panelShadow.getElementById('cfg-sel') || {}).value || ''; if (!cfg.selector) return; }
    if (action === 'scroll') {
      var posEl = panelShadow.getElementById('cfg-pos');
      if (posEl && posEl.value === 'element') { cfg.selector = (panelShadow.getElementById('cfg-sel') || {}).value || ''; }
      else if (posEl) { cfg.position = posEl.value; }
      else { cfg.position = 'top'; }
    }
    if (action === 'js') { cfg.code = (panelShadow.getElementById('cfg-code') || {}).value || ''; if (!cfg.code) return; }
    var lbl = (panelShadow.getElementById('label-input') || {}).value || '';
    if (editing) {
      var idx = shortcuts.findIndex(function(s) { return s.id === editing; });
      if (idx !== -1) {
        shortcuts[idx].shortcut = recordedCombo;
        shortcuts[idx].action = action;
        shortcuts[idx].config = cfg;
        shortcuts[idx].label = lbl;
      }
    } else {
      shortcuts.push({ id: genId(), shortcut: recordedCombo, action: action, config: cfg, label: lbl, createdAt: new Date().toISOString() });
    }
    save();
    editing = null; recording = false;
    renderList();
  };

  // Wire delete in form
  var formDel = panelShadow.getElementById('form-del');
  if (formDel) formDel.onclick = function() {
    shortcuts = shortcuts.filter(function(s) { return s.id !== editing; });
    save(); editing = null; renderList();
  };
}

