  return '* {box-sizing:border-box;margin:0;padding:0} ' +
    '.panel {width:360px;max-height:60vh;overflow:hidden;display:flex;flex-direction:column;background:#161b22;border:1px solid #30363d;border-radius:12px;font:13px/1.5 -apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,sans-serif;color:#c9d1d9;box-shadow:0 8px 32px rgba(0,0,0,.4)} ' +
    '.hdr {display:flex;align-items:center;gap:8px;padding:10px 14px;border-bottom:1px solid #21262d} ' +
    '.title {font-weight:700;font-size:13px;color:#e6edf3} .sub {font-size:11px;color:#8b949e;margin-left:auto} ' +
    '.x {background:none;border:none;color:#8b949e;font-size:14px;cursor:pointer;padding:2px 6px;line-height:1;margin-left:4px;font-weight:600} .x:hover {color:#e6edf3} ' +
    '.body {padding:12px 14px;overflow-y:auto;max-height:calc(60vh - 44px)} ' +
    '.btn {padding:6px 12px;border-radius:6px;border:1px solid #30363d;background:#21262d;color:#c9d1d9;font:inherit;font-size:12px;font-weight:600;cursor:pointer} .btn:hover {background:#30363d} ' +
    '.bp {background:#238636;border-color:#238636;color:#fff;width:100%;margin-bottom:10px} .bp:hover {background:#2ea043} ' +
    '.bd {background:rgba(248,81,73,.1);border-color:#da3633;color:#f85149} .bd:hover {background:rgba(248,81,73,.2)} ' +
    '.bs {padding:3px 8px;font-size:11px} ' +
    '.list {display:flex;flex-direction:column;gap:4px} ' +
    '.item {display:flex;align-items:center;gap:8px;padding:6px 8px;background:#0d1117;border:1px solid #21262d;border-radius:6px} ' +
    '.item-dim {opacity:0.6} ' +
    '.info {display:flex;flex-direction:column;gap:2px;overflow:hidden;flex:1} ' +
