    '.tag {font-size:9px;color:#8b949e;text-transform:uppercase;letter-spacing:0.5px} ' +
    'code {font-size:11px;color:#79c0ff;background:rgba(56,139,253,.1);padding:1px 5px;border-radius:4px;white-space:nowrap;flex-shrink:0} ' +
    '.empty {text-align:center;padding:12px;color:#484f58;font-size:12px} ' +
