    '.rl input {accent-color:#58a6ff} ' +
    '.row {display:flex;gap:6px;align-items:center} ' +
    'select {padding:6px 8px;border-radius:6px;border:1px solid #30363d;background:#0d1117;color:#c9d1d9;font:inherit;font-size:12px}';
}

// ── Init ──
api.addEventListener(window, 'message', function(e) {
  if (!e.data || !e.data.__domo) return;
  if (e.data.type === 'domo:command' && e.data.command === 'toggle-shortcuts-panel') {
    if (panelOpen) closePanel(); else openPanel();
  }
  if (e.data.type === 'domo:openPanel' && e.data.pluginId === api.pluginId) {
    if (panelOpen) closePanel(); else openPanel();
  }
});

api.onCleanup(function() {
  closePanel();
});
